#raw suppressPackageStartupMessages({ library(WGCNA) library(DESeq2) library(dplyr) library(ggplot2) library(reshape2) })
options(stringsAsFactors = FALSE) enableWGCNAThreads()
args <- commandArgs(trailingOnly = TRUE)
## Parse arguments mode <- args[1] input_a <- args[2] # primary expression matrix / raw counts / tpm input_b <- args[3] # secondary matrix (consensus) / coldata (DESeq2) / NULL input_c <- args[4] # condition col (DESeq2) / NULL input_d <- args[5] # sample annotation (recount3) / NULL sample_col <- args[6] # sample ID column trait_col_or_auto <- args[7] # trait column / recount3 trait col trait_file <- args[8] # external trait file / NULL trait_col <- args[9] # trait column in external file
soft_power_arg <- as.integer(args[10]) min_module_size <- as.integer(args[11]) var_genes_pct <- as.numeric(args[12]) merge_cut_height <- as.numeric(args[13]) network_type <- args[14] cor_type <- args[15]
out_membership <- args[16] out_hub <- args[17] out_trait_cor <- args[18] out_edges <- args[19] out_soft_plot <- args[20] out_dendro_plot <- args[21] out_heatmap_plot <- args[22]
## ============================================================ ## Helper functions ## ============================================================
write_tab <- function(x, path) { write.table(x, path, sep = "\t", quote = FALSE, row.names = TRUE, col.names = NA) }
filter_var_genes <- function(mat, pct) { vars <- apply(mat, 1, var) top_n <- max(1, round(nrow(mat) * pct)) mat[order(vars, decreasing = TRUE)[1:top_n], ] }
pick_soft_power <- function(datExpr, network_type) { powers <- c(1:10, seq(12, 20, by = 2)) sft <- pickSoftThreshold(datExpr, powerVector = powers, networkType = network_type, verbose = 0) best <- sft$powerEstimate if (is.na(best)) { warning("Auto soft power selection failed; defaulting to 6.") best <- 6 } cat("Soft-thresholding power selected:", best, "\n") best }
## ============================================================ ## Mode 3: Two datasets -> Consensus WGCNA ## Expects: two pre-normalized expression matrices (genes x samples) ## ============================================================
if (mode == "3") { cat("Mode 3: Consensus WGCNA across two datasets\n") expr1 <- t(as.matrix(read.delim(input_a, row.names = 1, check.names = FALSE))) expr2 <- t(as.matrix(read.delim(input_b, row.names = 1, check.names = FALSE)))
## Align genes common_genes <- intersect(colnames(expr1), colnames(expr2)) if (length(common_genes) == 0) stop("No common genes between the two datasets.") expr1 <- expr1[, common_genes, drop = FALSE] expr2 <- expr2[, common_genes, drop = FALSE]
multiExpr <- list( Set1 = list(data = expr1), Set2 = list(data = expr2) )
## Filter variable genes per dataset top_n <- max(1, round(length(common_genes) * var_genes_pct)) vars1 <- apply(expr1, 2, var) vars2 <- apply(expr2, 2, var) top_genes <- intersect( names(sort(vars1, decreasing = TRUE))[1:top_n], names(sort(vars2, decreasing = TRUE))[1:top_n] ) if (length(top_genes) == 0) stop("No overlapping variable genes for consensus WGCNA.") multiExpr[[1]]$data <- expr1[, top_genes, drop = FALSE] multiExpr[[2]]$data <- expr2[, top_genes, drop = FALSE]
## Consensus soft power if (soft_power_arg == 0) { powers <- c(1:10, seq(12, 20, by = 2)) sft <- consensusSoftThresholdPower(multiExpr, powerVector = powers, networkType = network_type, verbose = 0) soft_power <- sft$powerEstimate if (is.na(soft_power)) soft_power <- 6 } else { soft_power <- soft_power_arg } cat("Consensus soft power:", soft_power, "\n")
## Consensus module detection net <- blockwiseConsensusModules( multiExpr, power = soft_power, minModuleSize = min_module_size, mergeCutHeight = merge_cut_height, networkType = network_type, TOMType = "unsigned", numericLabels = FALSE, saveTOMs = FALSE, verbose = 0 )
## Use dataset 1 as reference for downstream outputs datExpr <- multiExpr[[1]]$data moduleColors <- labels2colors(net$moduleLabels[, 1]) MEs <- net$multiMEs[[1]]$data
if (trait_file != "NULL") { traits <- read.delim(trait_file, row.names = 1, check.names = FALSE) traitData <- traits[rownames(datExpr), , drop = FALSE] } else { traitData <- NULL }
## Skip shared network block; write outputs directly mm <- moduleColors hub_list <- chooseTopHubInEachModule(datExpr, mm, power = soft_power, type = network_type)
membership_df <- data.frame( Gene = colnames(datExpr), Module = mm, stringsAsFactors = FALSE ) write_tab(membership_df, out_membership) write_tab(data.frame(Module = names(hub_list), HubGene = hub_list), out_hub)
if (!is.null(traitData)) { cor_mat <- cor(MEs, traitData, use = "pairwise.complete.obs") write_tab(as.data.frame(cor_mat), out_trait_cor) } else { write_tab(data.frame(Note = "No trait data provided"), out_trait_cor) }
adj <- adjacency(datExpr, power = soft_power, type = network_type) edges <- melt(adj) colnames(edges) <- c("Gene1", "Gene2", "Weight") edges <- edges[edges$Weight > 0.1 & as.character(edges$Gene1) < as.character(edges$Gene2), ] write_tab(edges, out_edges) cat("Consensus WGCNA complete.\n") quit(status = 0) }
## ============================================================ ## Mode 4: Recount3 direct integration ## Expects: TPM matrix (genes x samples) + sample annotation tabular ## ============================================================
if (mode == "4") { cat("Mode 4: Recount3 direct integration (TPM + sample annotation)\n") tpm <- read.delim(input_a, row.names = 1, check.names = FALSE) annot <- read.delim(input_d, row.names = 1, check.names = FALSE)
sample_id_col <- sample_col tpm_trait_col <- trait_col_or_auto # maps to recount3 'tool_tissue_label' or user-defined
## Match samples using sample_id_col from annotation if (sample_id_col != "NULL" && sample_id_col %in% colnames(annot)) { annot_ids <- as.character(annot[[sample_id_col]]) } else { annot_ids <- rownames(annot) } common <- intersect(colnames(tpm), annot_ids) if (length(common) == 0) stop("No common samples between TPM matrix and sample annotation.") tpm <- tpm[, match(common, colnames(tpm)), drop = FALSE] annot <- annot[match(common, annot_ids), , drop = FALSE]
datExpr <- t(as.matrix(tpm))
## Build numeric trait from annotation column if (tpm_trait_col != "NULL" && tpm_trait_col %in% colnames(annot)) { trait_vals <- as.numeric(as.factor(annot[[tpm_trait_col]])) traitData <- data.frame(trait_vals, row.names = rownames(datExpr)) colnames(traitData) <- tpm_trait_col } else { warning("Trait column '", tpm_trait_col, "' not found in annotation; skipping trait correlation.") traitData <- NULL } }
## ============================================================ ## Shared WGCNA pipeline (Modes 1, 2, 4) ## ============================================================
## Filter variable genes if (mode != "3") { cat("Filtering to top", var_genes_pct * 100, "% variable genes\n") datExpr <- t(filter_var_genes(t(datExpr), var_genes_pct)) datExpr <- t(datExpr) # back to samples x genes }
## Goodness check gsg <- goodSamplesGenes(datExpr, verbose = 0) if (!gsg$allOK) { cat("Removing", sum(!gsg$goodGenes), "bad genes and", sum(!gsg$goodSamples), "bad samples\n") datExpr <- datExpr[gsg$goodSamples, gsg$goodGenes] }
## Soft-thresholding power if (soft_power_arg == 0) { soft_power <- pick_soft_power(datExpr, network_type) } else { soft_power <- soft_power_arg }
## Soft power diagnostic plot if (out_soft_plot != "NULL") { powers <- c(1:10, seq(12, 20, by = 2)) sft <- pickSoftThreshold(datExpr, powerVector = powers, networkType = network_type, verbose = 0) png(out_soft_plot, width = 900, height = 450) par(mfrow = c(1, 2)) plot(sft$fitIndices[, 1], -sign(sft$fitIndices[, 3]) * sft$fitIndices[, 2], xlab = "Soft Threshold (power)", ylab = "Scale Free Topology Model Fit, signed R^2", main = "Scale independence", type = "n") text(sft$fitIndices[, 1], -sign(sft$fitIndices[, 3]) * sft$fitIndices[, 2], labels = powers, col = "red") abline(h = 0.90, col = "red") plot(sft$fitIndices[, 1], sft$fitIndices[, 5], xlab = "Soft Threshold (power)", ylab = "Mean Connectivity", main = "Mean connectivity", type = "n") text(sft$fitIndices[, 1], sft$fitIndices[, 5], labels = powers, col = "red") dev.off() }
## Network construction & module detection cat("Building network with power =", soft_power, "\n") net <- blockwiseModules( datExpr, power = soft_power, networkType = network_type, TOMType = "unsigned", minModuleSize = min_module_size, mergeCutHeight = merge_cut_height, numericLabels = FALSE, pamRespectsDendro = FALSE, saveTOMs = FALSE, verbose = 0, corType = cor_type )
moduleColors <- net$colors MEs <- net$MEs
## Dendrogram plot if (out_dendro_plot != "NULL") { png(out_dendro_plot, width = 1200, height = 600) plotDendroAndColors( net$dendrograms[[1]], moduleColors[net$blockGenes[[1]]], "Module colors", dendroLabels = FALSE, hang = 0.03, addGuide = TRUE, guideHang = 0.05, main = "Gene dendrogram and module colors" ) dev.off() }
## Module membership membership_df <- data.frame( Gene = colnames(datExpr), Module = moduleColors, stringsAsFactors = FALSE ) write_tab(membership_df, out_membership) cat("Module membership written:", nrow(membership_df), "genes\n")
## Hub genes (one per module) hub_list <- chooseTopHubInEachModule(datExpr, moduleColors, power = soft_power, type = network_type) hub_df <- data.frame(Module = names(hub_list), HubGene = as.character(hub_list), stringsAsFactors = FALSE) write_tab(hub_df, out_hub) cat("Hub genes written:", nrow(hub_df), "modules\n")
## Module-trait correlation if (!is.null(traitData)) { traitData_aligned <- traitData[rownames(datExpr), , drop = FALSE] cor_mat <- cor(MEs, traitData_aligned, use = "pairwise.complete.obs") pval_mat <- corPvalueStudent(cor_mat, nrow(datExpr)) write_tab(as.data.frame(cor_mat), out_trait_cor)
## Heatmap plot if (out_heatmap_plot != "NULL") { png(out_heatmap_plot, width = max(600, ncol(cor_mat) * 80), height = max(600, nrow(cor_mat) * 30)) labeledHeatmap( Matrix = cor_mat, xLabels = colnames(traitData_aligned), yLabels = rownames(cor_mat), ySymbols = rownames(cor_mat), colorMatrix = numbers2colors(cor_mat, signed = TRUE), colors = greenWhiteRed(50), textMatrix = paste0(signif(cor_mat, 2), "\n(", signif(pval_mat, 1), ")"), setStdMargins = FALSE, cex.text = 0.5, zlim = c(-1, 1), main = "Module-trait relationships" ) dev.off() } } else { write_tab(data.frame(Note = "No trait data provided for correlation"), out_trait_cor) }
## Network edge list (adjacency > 0.1, upper triangle only) cat("Computing adjacency for edge list...\n") adj <- adjacency(datExpr, power = soft_power, type = network_type) edges <- melt(adj) colnames(edges) <- c("Gene1", "Gene2", "Weight") edges <- edges[ edges$Weight > 0.1 & as.character(edges$Gene1) < as.character(edges$Gene2), ] write_tab(edges, out_edges) cat("Network edges written:", nrow(edges), "edges\n")
cat("WGCNA complete.\n") #end raw
